  // ── Deterministic integrity helpers ──
  // textCharCount: count visible text characters in HTML (strips tags/scripts/styles)
  const textCharCount = (html) => {
    if (!html) return 0;
    return String(html)
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]*>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&[a-z]+;/gi, ' ')
      .replace(/\s+/g, ' ')
      .trim().length;
  };

