  // eval-sliced by tests) — a parity golden holds them together.
  const _alloNormForCoverage = (s) => String(s || '')
    .replace(/(\p{L})[-­]\s+(\p{L})/gu, '$1$2')
    .replace(/­/g, '')
    .replace(/\s+/g, ' ')
