          const _arSetOf = (s) => { const o = new Set(); for (const p of String(s || '').split(/\s+/)) { const n = _arNorm(p); if (n.length >= 2) o.add(n); } return o; };
          const _arSetT = _arSetOf(_arTess);
          const _arSetV = _arSetOf(_arVis);
