      var _gs = String(raw == null ? '' : raw).trim();
      if (_gs.indexOf('```') !== -1) { var _gp = _gs.split('```'); _gs = (_gp[1] || _gp[0] || '').replace(/^\s*(?:json|js)\s*/i, '').trim(); if (_gs.lastIndexOf('```') !== -1) _gs = _gs.substring(0, _gs.lastIndexOf('```')).trim(); }
