        const winEnd = Math.min(srcWordsLc.length - 1, pos + 5);
        const beforeCtx = srcWordsLc.slice(winStart, pos).filter(Boolean);
        const afterCtx = srcWordsLc.slice(pos + 1, winEnd + 1).filter(Boolean);
